    "contacts.linked_records": "Bağlı kayıtlar",
    "contacts.no_linked_records": "Bu kişiye henüz bağlı aday veya alıcı yok. Birini oluşturmak için yukarıdan dönüştürün.",
    "contacts.open_detail": "Bağlı kayıtlar ve eylemler",
