    "crm.pipeline_value": "Hat",
    "crm.select_account": "- Hesap seçin -",
    "crm.stage_history": "Aşama geçmişi",
    "crm.stepper_hint": "Anlaşmayı taşımak için bir aşamaya tıklayın. Kazanılan / kaybedilen aşamalar aşağıdaki Kazan / Kaybet düğmeleriyle kapatılır.",
