    "modules.dev_rules_title": "Temel kurallar (PR incelemesinde zorunlu)",
    "modules.dev_step_copy": "Şablondan iskelet oluşturun",
    "modules.dev_step_manifest": "Manifest'i düzenleyin",
    "modules.dev_step_models": "Model ve şema ekleyin (isteğe bağlı)",
    "modules.dev_step_restart": "Yeniden başlatın ve etkinleştirin",
    "modules.dev_step_router": "Router ekleyin",
